{"path": "/tmp/isolated_workspace_1091/game.html", "content": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Pokémon Gen 3 Battle</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body {
  background: #111;
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
  overflow: hidden;
  font-family: monospace;
}
canvas {
  image-rendering: pixelated;
  image-rendering: -moz-crisp-edges;
  image-rendering: crisp-edges;
}
#gameCanvas {
  border: 4px solid #333;
}
</style>
</head>
<body>
<canvas id="gameCanvas"></canvas>
<script>
// ============================================================
// POKÉMON GEN 3 STYLE HTML5 GAME
// Single-file: Map Exploration → Battle Transition → Full Battle
// ============================================================

const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

// GBA resolution scaled 3x
const GBA_W = 240, GBA_H = 160, SCALE = 3;
canvas.width = GBA_W * SCALE;
canvas.height = GBA_H * SCALE;
ctx.imageSmoothingEnabled = false;

// Offscreen buffer at native GBA resolution
const buf = document.createElement('canvas');
buf.width = GBA_W; buf.height = GBA_H;
const bctx = buf.getContext('2d');
bctx.imageSmoothingEnabled = false;

// ============================================================
// ASSET MANAGER
// ============================================================
const AssetManager = {
  assets: {},
  loaded: 0,
  total: 0,
  allLoaded: false,
  errors: [],

  queue(key, url) {
    this.total++;
    this.assets[key] = { url, img: null, loaded: false, error: false };
  },

  loadAll() {
    return new Promise((resolve) => {
      if (this.total === 0) { this.allLoaded = true; resolve(); return; }
      Object.keys(this.assets).forEach(key => {
        const a = this.assets[key];
        const img = new Image();
        img.crossOrigin = 'anonymous';
        img.onload = () => {
          a.img = img; a.loaded = true;
          this.loaded++;
          if (this.loaded >= this.total) { this.allLoaded = true; resolve(); }
        };
        img.onerror = () => {
          a.error = true; a.loaded = true;
          this.errors.push(key);
          this.loaded++;
          if (this.loaded >= this.total) { this.allLoaded = true; resolve(); }
        };
        img.src = a.url;
      });
    });
  },

  get(key) {
    const a = this.assets[key];
    if (!a || a.error || !a.img) return null;
    return a.img;
  },

  progress() {
    return this.total === 0 ? 1 : this.loaded / this.total;
  }
};

