// Type effectiveness chart (attacker type → defender type → multiplier)
// 0=immune, 0.5=not very effective, 1=neutral, 2=super effective
const TYPE_CHART = (() => {
  const c = Array.from({length:17}, () => new Float32Array(17).fill(1));
  const se = (a,d) => c[a][d] = 2;
  const nve = (a,d) => c[a][d] = 0.5;
  const imm = (a,d) => c[a][d] = 0;

  // Normal
  nve(TYPES.NORMAL, TYPES.ROCK); nve(TYPES.NORMAL, TYPES.STEEL);
  imm(TYPES.NORMAL, TYPES.GHOST);
  // Fighting
  se(TYPES.FIGHTING, TYPES.NORMAL); se(TYPES.FIGHTING, TYPES.ROCK);
  se(TYPES.FIGHTING, TYPES.STEEL); se(TYPES.FIGHTING, TYPES.ICE);
  se(TYPES.FIGHTING, TYPES.DARK);
  nve(TYPES.FIGHTING, TYPES.FLYING); nve(TYPES.FIGHTING, TYPES.POISON);
  nve(TYPES.FIGHTING, TYPES.BUG); nve(TYPES.FIGHTING, TYPES.PSYCHIC);
  imm(TYPES.FIGHTING, TYPES.GHOST);
  // Flying
  se(TYPES.FLYING, TYPES.FIGHTING); se(TYPES.FLYING, TYPES.BUG);
  se(TYPES.FLYING, TYPES.GRASS);
  nve(TYPES.FLYING, TYPES.ROCK); nve(TYPES.FLYING, TYPES.STEEL);
  nve(TYPES.FLYING, TYPES.ELECTRIC);
  // Poison
  se(TYPES.POISON, TYPES.GRASS);
  nve(TYPES.POISON, TYPES.POISON); nve(TYPES.POISON, TYPES.GROUND);
  nve(TYPES.POISON, TYPES.ROCK); nve(TYPES.POISON, TYPES.GHOST);
  imm(TYPES.POISON, TYPES.STEEL);
  // Ground
  se(TYPES.GROUND, TYPES.POISON); se(TYPES.GROUND, TYPES.ROCK);
  se(TYPES.GROUND, TYPES.STEEL); se(TYPES.GROUND, TYPES.FIRE);
  se(TYPES.GROUND, TYPES.ELECTRIC);
  nve(TYPES.GROUND, TYPES.BUG); nve(TYPES.GROUND, TYPES.GRASS);
  imm(TYPES.GROUND, TYPES.FLYING);
  // Rock
  se(TYPES.ROCK, TYPES.FLYING); se(TYPES.ROCK, TYPES.BUG);
  se(TYPES.ROCK, TYPES.FIRE); se(TYPES.ROCK, TYPES.ICE);
  nve(TYPES.ROCK, TYPES.FIGHTING); nve(TYPES.ROCK, TYPES.GROUND);
  nve(TYPES.ROCK, TYPES.STEEL);
  // Bug
  se(TYPES.BUG, TYPES.GRASS); se(TYPES.BUG, TYPES.PSYCHIC);
  se(TYPES.BUG, TYPES.DARK);
  nve(TYPES.BUG, TYPES.FIGHTING); nve(TYPES.BUG, TYPES.FLYING);
  nve(TYPES.BUG, TYPES.POISON); nve(TYPES.BUG, TYPES.GHOST);
  nve(TYPES.BUG, TYPES.STEEL); nve(TYPES.BUG, TYPES.FIRE);
  // Ghost
  se(TYPES.GHOST, TYPES.GHOST); se(TYPES.GHOST, TYPES.PSYCHIC);
  nve(TYPES.GHOST, TYPES.DARK); nve(TYPES.GHOST, TYPES.STEEL);
  imm(TYPES.GHOST, TYPES.NORMAL);
  // Steel
  se(TYPES.STEEL, TYPES.ROCK); se(TYPES.STEEL, TYPES.ICE);
  nve(TYPES.STEEL, TYPES.STEEL); nve(TYPES.STEEL, TYPES.FIRE);
  nve(TYPES.STEEL, TYPES.WATER); nve(TYPES.STEEL, TYPES.ELECTRIC);
  // Fire
  se(TYPES.FIRE, TYPES.BUG); se(TYPES.FIRE, TYPES.STEEL);
  se(TYPES.FIRE, TYPES.GRASS); se(TYPES.FIRE, TYPES.ICE);
  nve(TYPES.FIRE, TYPES.ROCK); nve(TYPES.FIRE, TYPES.FIRE);
  nve(TYPES.FIRE, TYPES.WATER); nve(TYPES.FIRE, TYPES.DRAGON);
  // Water
  se(TYPES.WATER, TYPES.GROUND); se(TYPES.WATER, TYPES.ROCK);
  se(TYPES.WATER, TYPES.FIRE);
  nve(TYPES.WATER, TYPES.WATER); nve(TYPES.WATER, TYPES.GRASS);
  nve(TYPES.WATER, TYPES.DRAGON);
  // Grass
  se(TYPES.GRASS, TYPES.GROUND); se(TYPES.GRASS, TYPES.ROCK);
  se(TYPES.GRASS, TYPES.WATER);
  nve(TYPES.GRASS, TYPES.FLYING); nve(TYPES.GRASS, TYPES.POISON);
  nve(TYPES.GRASS, TYPES.BUG); nve(TYPES.GRASS, TYPES.STEEL);
  nve(TYPES.GRASS, TYPES.FIRE); nve(TYPES.GRASS, TYPES.GRASS);
