  se(TYPES.ELECTRIC, TYPES.FLYING); se(TYPES.ELECTRIC, TYPES.WATER);
  nve(TYPES.ELECTRIC, TYPES.GRASS); nve(TYPES.ELECTRIC, TYPES.ELECTRIC);
  nve(TYPES.ELECTRIC, TYPES.DRAGON);
  imm(TYPES.ELECTRIC, TYPES.GROUND);
  // Psychic
  se(TYPES.PSYCHIC, TYPES.FIGHTING); se(TYPES.PSYCHIC, TYPES.POISON);
  nve(TYPES.PSYCHIC, TYPES.STEEL); nve(TYPES.PSYCHIC, TYPES.PSYCHIC);
  imm(TYPES.PSYCHIC, TYPES.DARK);
  // Ice
  se(TYPES.ICE, TYPES.FLYING); se(TYPES.ICE, TYPES.GROUND);
  se(TYPES.ICE, TYPES.GRASS); se(TYPES.ICE, TYPES.DRAGON);
  nve(TYPES.ICE, TYPES.STEEL); nve(TYPES.ICE, TYPES.FIRE);
  nve(TYPES.ICE, TYPES.WATER); nve(TYPES.ICE, TYPES.ICE);
  // Dragon
  se(TYPES.DRAGON, TYPES.DRAGON);
  nve(TYPES.DRAGON, TYPES.STEEL);
  // Dark
  se(TYPES.DARK, TYPES.GHOST); se(TYPES.DARK, TYPES.PSYCHIC);
  nve(TYPES.DARK, TYPES.FIGHTING); nve(TYPES.DARK, TYPES.DARK);
  nve(TYPES.DARK, TYPES.STEEL);

  return c;
})();

function getEffectiveness(moveType, defTypes) {
  let mult = 1;
  for (const dt of defTypes) mult *= TYPE_CHART[moveType][dt];
  return mult;
}

