// ============================================================
// MAP ENGINE
// ============================================================
const TILE = 16;
const MAP_W = 20, MAP_H = 15;

// Tile types: 0=grass, 1=road, 2=tall_grass, 3=tree, 4=flower
const MAP_DATA = (() => {
  const m = Array.from({length: MAP_H}, () => new Uint8Array(MAP_W).fill(0));
  // Roads
  for (let x = 3; x < 17; x++) { m[7][x] = 1; m[8][x] = 1; }
  for (let y = 2; y < 13; y++) { m[y][9] = 1; m[y][10] = 1; }
  // Tall grass patches
  for (let y = 3; y < 7; y++) for (let x = 2; x < 5; x++) m[y][x] = 2;
  for (let y = 9; y < 13; y++) for (let x = 13; x < 17; x++) m[y][x] = 2;
  // Trees (border + scattered)
  for (let x = 0; x < MAP_W; x++) { m[0][x] = 3; m[MAP_H-1][x] = 3; }
  for (let y = 0; y < MAP_H; y++) { m[y][0] = 3; m[y][MAP_W-1] = 3; }
  m[3][7] = 3; m[4][14] = 3; m[11][5] = 3; m[5][16] = 3;
  m[2][13] = 3; m[12][3] = 3;
  // Flowers
  m[5][3] = 4; m[10][14] = 4; m[6][12] = 4; m[3][15] = 4;
  return m;
})();

function isWalkable(tx, ty) {
  if (tx < 0 || ty < 0 || tx >= MAP_W || ty >= MAP_H) return false;
  const t = MAP_DATA[ty][tx];
  return t !== 3; // trees block
}

function drawTile(x, y, tile) {
  const px = x * TILE, py = y * TILE;
  switch(tile) {
    case 0: // grass
      bctx.fillStyle = '#88c070';
      bctx.fillRect(px, py, TILE, TILE);
      // Subtle grass texture
      bctx.fillStyle = '#78b860';
      for (let i = 0; i < 3; i++) {
        const gx = px + ((x*7+i*5)%13), gy = py + ((y*11+i*3)%13);
        bctx.fillRect(gx, gy, 2, 3);
      }
      break;
    case 1: // road
      bctx.fillStyle = '#c8b87c';
      bctx.fillRect(px, py, TILE, TILE);
      bctx.fillStyle = '#b8a86c';
      bctx.fillRect(px, py, TILE, 1);
      break;
    case 2: // tall grass
      bctx.fillStyle = '#88c070';
      bctx.fillRect(px, py, TILE, TILE);
      bctx.fillStyle = '#48a030';
      for (let i = 0; i < 5; i++) {
        const gx = px + (i * 3) % TILE, gy = py + 4 + (i * 7) % 10;
        bctx.fillRect(gx, gy, 2, 5);
        bctx.fillRect(gx+1, gy-1, 1, 1);
      }
      break;
    case 3: // tree
      bctx.fillStyle = '#88c070';
      bctx.fillRect(px, py, TILE, TILE);
      bctx.fillStyle = '#5a3a1a';
      bctx.fillRect(px+6, py+10, 4, 6);
      bctx.fillStyle = '#2d8a2d';
      bctx.fillRect(px+2, py+2, 12, 10);
      bctx.fillStyle = '#3a9a3a';
      bctx.fillRect(px+3, py+3, 10, 8);
      break;
    case 4: // flower
      bctx.fillStyle = '#88c070';
      bctx.fillRect(px, py, TILE, TILE);
      bctx.fillStyle = '#e05050';
      bctx.fillRect(px+6, py+5, 4, 4);
      bctx.fillStyle = '#f0e040';
      bctx.fillRect(px+7, py+6, 2, 2);
      bctx.fillStyle = '#48a030';
      bctx.fillRect(px+7, py+9, 2, 4);
      break;
  }
}

// ============================================================
// PLAYER & NPC
// ============================================================
const Player = {
  tx: 5, ty: 7, // tile position
  px: 5*TILE, py: 7*TILE, // pixel position
  dir: 1, // 0=up,1=down,2=left,3=right
  moving: false,
  moveProgress: 0,
  fromPx: 0, fromPy: 0,
  toPx: 0, toPy: 0,
  animFrame: 0,
  animTimer: 0,

  draw() {
    const x = this.px, y = this.py;
    // Body
    bctx.fillStyle = '#3040a0'; // blue shirt
    bctx.fillRect(x+4, y+6, 8, 6);
    // Head
    bctx.fillStyle = '#f0c8a0'; // skin
    bctx.fillRect(x+5, y+1, 6, 6);
    // Hair/hat
    bctx.fillStyle = '#f02020';
    bctx.fillRect(x+4, y+0, 8, 3);
    if (this.dir === 1) { // facing down - show eyes
      bctx.fillStyle = '#202020';
      bctx.fillRect(x+6, y+4, 1, 1);
      bctx.fillRect(x+9, y+4, 1, 1);
    } else if (this.dir === 0) { // facing up
      bctx.fillStyle = '#f02020';
      bctx.fillRect(x+4, y+1, 8, 4);
    } else { // left/right
      bctx.fillStyle = '#202020';
      const ex = this.dir === 2 ? x+6 : x+8;
      bctx.fillRect(ex, y+4, 1, 1);
    }
    // Legs
    bctx.fillStyle = '#404040';
    const legOffset = this.moving ? (Math.sin(this.animFrame * Math.PI) * 2) : 0;
    bctx.fillRect(x+5, y+12, 3, 4 + (legOffset > 0 ? 0 : 1));
    bctx.fillRect(x+9, y+12, 3, 4 + (legOffset <= 0 ? 0 : 1));
  },

  update(dt) {
    if (this.moving) {
      this.moveProgress += dt * 4; // speed
      if (this.moveProgress >= 1) {
        this.moveProgress = 0;
        this.px = this.toPx;
        this.py = this.toPy;
        this.moving = false;
      } else {
        this.px = this.fromPx + (this.toPx - this.fromPx) * this.moveProgress;
        this.py = this.fromPy + (this.toPy - this.fromPy) * this.moveProgress;
      }
      this.animTimer += dt;
      if (this.animTimer > 0.15) { this.animTimer = 0; this.animFrame = 1 - this.animFrame; }
      return;
    }

    let dx = 0, dy = 0;
    if (Input.isDown('ArrowUp'))    { dy = -1; this.dir = 0; }
    else if (Input.isDown('ArrowDown'))  { dy = 1; this.dir = 1; }
    else if (Input.isDown('ArrowLeft'))  { dx = -1; this.dir = 2; }
    else if (Input.isDown('ArrowRight')) { dx = 1; this.dir = 3; }

    if (dx !== 0 || dy !== 0) {
      const ntx = this.tx + dx, nty = this.ty + dy;
      if (isWalkable(ntx, nty) && !(ntx === NPC.tx && nty === NPC.ty)) {
        this.fromPx = this.px; this.fromPy = this.py;
        this.tx = ntx; this.ty = nty;
        this.toPx = ntx * TILE; this.toPy = nty * TILE;
        this.moving = true;
        this.moveProgress = 0;
      }
    }
  }
};

const NPC = {
  tx: 10, ty: 5,
  dir: 1,

  draw() {
    const x = this.tx * TILE, y = this.ty * TILE;
    // Body
    bctx.fillStyle = '#808080';
    bctx.fillRect(x+4, y+6, 8, 6);
    // Head
    bctx.fillStyle = '#f0c8a0';
    bctx.fillRect(x+5, y+1, 6, 6);
    // Hair
    bctx.fillStyle = '#604020';
    bctx.fillRect(x+4, y+0, 8, 3);
    // Eyes (always facing player direction)
    bctx.fillStyle = '#202020';
    bctx.fillRect(x+6, y+4, 1, 1);
    bctx.fillRect(x+9, y+4, 1, 1);
    // Legs
    bctx.fillStyle = '#303030';
    bctx.fillRect(x+5, y+12, 3, 4);
    bctx.fillRect(x+9, y+12, 3, 4);
    // Exclamation mark if player is near
    if (isNearNPC()) {
      bctx.fillStyle = '#f0e020';
      bctx.fillRect(x+7, y-6, 2, 4);
      bctx.fillRect(x+7, y-1, 2, 2);
    }
  }
};

function isNearNPC() {
  return Math.abs(Player.tx - NPC.tx) + Math.abs(Player.ty - NPC.ty) <= 1;
}

function isFacingNPC() {
  let ftx = Player.tx, fty = Player.ty;
  if (Player.dir === 0) fty--;
  else if (Player.dir === 1) fty++;
  else if (Player.dir === 2) ftx--;
  else ftx++;
  return ftx === NPC.tx && fty === NPC.ty;
}

// ============================================================
// DIALOG SYSTEM
// ============================================================
const Dialog = {
  active: false,
  lines: [],
  currentLine: 0,
  charIndex: 0,
  charTimer: 0,
  charSpeed: 0.03,
  displayText: '',
  onComplete: null,
  waitingForInput: false,

  start(lines, onComplete) {
    this.active = true;
    this.lines = lines;
    this.currentLine = 0;
    this.charIndex = 0;
    this.charTimer = 0;
    this.displayText = '';
    this.onComplete = onComplete;
    this.waitingForInput = false;
  },

  update(dt) {
    if (!this.active) return;
    if (this.waitingForInput) {
      if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
        this.currentLine++;
        if (this.currentLine >= this.lines.length) {
          this.active = false;
          if (this.onComplete) this.onComplete();
          return;
        }
        this.charIndex = 0;
        this.displayText = '';
        this.waitingForInput = false;
      }
      return;
    }

    this.charTimer += dt;
    if (this.charTimer >= this.charSpeed) {
      this.charTimer = 0;
      if (this.charIndex < this.lines[this.currentLine].length) {
        this.displayText += this.lines[this.currentLine][this.charIndex];
        this.charIndex++;
      } else {
        this.waitingForInput = true;
      }
    }

    // Fast forward
    if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
      if (this.charIndex < this.lines[this.currentLine].length) {
        this.displayText = this.lines[this.currentLine];
        this.charIndex = this.lines[this.currentLine].length;
        this.waitingForInput = true;
      }
    }
  },

  draw() {
    if (!this.active) return;
    // Dialog box
    const bx = 4, by = GBA_H - 44, bw = GBA_W - 8, bh = 40;
    bctx.fillStyle = '#f8f8f8';
    bctx.fillRect(bx, by, bw, bh);
    bctx.strokeStyle = '#404040';
    bctx.lineWidth = 2;
    bctx.strokeRect(bx+1, by+1, bw-2, bh-2);
    bctx.lineWidth = 1;

    // Text
    bctx.fillStyle = '#202020';
    bctx.font = '8px monospace';
    bctx.textBaseline = 'top';

    // Word wrap
    const maxW = bw - 16;
    const words = this.displayText.split(' ');
    let line = '', lineY = by + 6;
    for (const word of words) {
      const test = line + (line ? ' ' : '') + word;
      if (bctx.measureText(test).width > maxW) {
        bctx.fillText(line, bx + 8, lineY);
        lineY += 12;
        line = word;
      } else {
        line = test;
      }
    }
    bctx.fillText(line, bx + 8, lineY);

    // Continue indicator
    if (this.waitingForInput) {
      const blinkOn = Math.floor(Date.now() / 400) % 2 === 0;
      if (blinkOn) {
        bctx.fillStyle = '#202020';
        const ax = bx + bw - 14, ay = by + bh - 10;
        bctx.beginPath();
        bctx.moveTo(ax, ay); bctx.lineTo(ax+6, ay); bctx.lineTo(ax+3, ay+4);
        bctx.fill();
      }
    }
  }
};

