// ============================================================
// MAP ENGINE
// ============================================================
const TILE = 16;
const MAP_W = 20, MAP_H = 15;

// Tile types: 0=grass, 1=road, 2=tall_grass, 3=tree, 4=flower
const MAP_DATA = (() => {
  const m = Array.from({length: MAP_H}, () => new Uint8Array(MAP_W).fill(0));
  // Roads
  for (let x = 3; x < 17; x++) { m[7][x] = 1; m[8][x] = 1; }
  for (let y = 2; y < 13; y++) { m[y][9] = 1; m[y][10] = 1; }
  // Tall grass patches
  for (let y = 3; y < 7; y++) for (let x = 2; x < 5; x++) m[y][x] = 2;
  for (let y = 9; y < 13; y++) for (let x = 13; x < 17; x++) m[y][x] = 2;
  // Trees (border + scattered)
  for (let x = 0; x < MAP_W; x++) { m[0][x] = 3; m[MAP_H-1][x] = 3; }
  for (let y = 0; y < MAP_H; y++) { m[y][0] = 3; m[y][MAP_W-1] = 3; }
  m[3][7] = 3; m[4][14] = 3; m[11][5] = 3; m[5][16] = 3;
  m[2][13] = 3; m[12][3] = 3;
  // Flowers
  m[5][3] = 4; m[10][14] = 4; m[6][12] = 4; m[3][15] = 4;
  return m;
})();

function isWalkable(tx, ty) {
  if (tx < 0 || ty < 0 || tx >= MAP_W || ty >= MAP_H) return false;
  const t = MAP_DATA[ty][tx];
  return t !== 3; // trees block
}

