const Battle = {
  active: false,
  state: 'intro', // intro, playerChoice, moveSelect, playerTurn, enemyTurn, message, fainted, result
  player: null,
  enemy: null,
  playerSprite: null,
  enemySprite: null,

  // Animation state
  introTimer: 0,
  playerSlideX: -96,
  enemySlideX: GBA_W + 96,

  // HP bar lerp
  playerHpDisplay: 1,
  enemyHpDisplay: 1,
  hpLerpSpeed: 0.8,

  // Message queue
  messages: [],
  currentMessage: '',
  msgCharIndex: 0,
  msgCharTimer: 0,
  msgWaiting: false,
  afterMessage: null,

  // Combat state
  selectedMove: 0,
  cursorPos: 0, // 0=Fight, 1=Bag, 2=Pokémon, 3=Run

  // Animation effects
  shakeTarget: null, // 'player' or 'enemy'
  shakeTimer: 0,
  flashTarget: null,
  flashTimer: 0,
  criticalFlash: false,

  // Slide-out for faint
  faintTarget: null,
  faintTimer: 0,

  // Result
  resultText: '',

  init(playerId, enemyId) {
    const pd = JSON.parse(JSON.stringify(POKEMON_DB[playerId]));
    const ed = JSON.parse(JSON.stringify(POKEMON_DB[enemyId]));
    pd.currentHp = pd.stats.hp;
    ed.currentHp = ed.stats.hp;

    this.player = pd;
    this.enemy = ed;
    this.playerSprite = AssetManager.get('player_back');
    this.enemySprite = AssetManager.get('enemy_front');
    this.active = true;
    this.state = 'intro';
    this.introTimer = 0;
    this.playerSlideX = -80;
    this.enemySlideX = GBA_W + 80;
    this.playerHpDisplay = 1;
    this.enemyHpDisplay = 1;
    this.messages = [];
    this.currentMessage = '';
    this.msgCharIndex = 0;
    this.shakeTarget = null;
    this.flashTarget = null;
    this.faintTarget = null;
    this.selectedMove = 0;
    this.cursorPos = 0;
    this.resultText = '';
  },

  showMessage(text, callback) {
    this.state = 'message';
    this.currentMessage = text;
    this.msgCharIndex = 0;
    this.msgCharTimer = 0;
    this.msgDisplayText = '';
    this.msgWaiting = false;
    this.afterMessage = callback || null;
  },

  showMessages(msgs, finalCallback) {
    if (msgs.length === 0) { if (finalCallback) finalCallback(); return; }
    const msg = msgs.shift();
    this.showMessage(msg, () => this.showMessages(msgs, finalCallback));
  },

  // Gen3 damage formula
  calcDamage(attacker, defender, move) {
    const level = attacker.level;
    const power = move.power;
    const isSpecial = isSpecialType(move.type);
    const A = isSpecial ? attacker.stats.spa : attacker.stats.atk;
    const D = isSpecial ? defender.stats.spd : defender.stats.def;

    let damage = Math.floor(((2 * level / 5 + 2) * power * A / D) / 50) + 2;

    // Critical hit (6.25% = 1/16)
    const isCritical = Math.random() < 1/16;
    if (isCritical) damage *= 2;

    // STAB
    const hasStab = attacker.types.includes(move.type);
    if (hasStab) damage = Math.floor(damage * 1.5);

    // Type effectiveness
    const effectiveness = getEffectiveness(move.type, defender.types);
    damage = Math.floor(damage * effectiveness);

    // Random factor (85-100)/100
    const rand = Math.floor(Math.random() * 16 + 85) / 100;
    damage = Math.floor(damage * rand);

    return { damage: Math.max(1, damage), isCritical, effectiveness, hasStab };
  },

  // Enemy AI
  chooseEnemyMove() {
    const moves = this.enemy.moves.filter(m => m.pp > 0);
    if (moves.length === 0) return null;

    // Prioritize super effective moves
    let bestMoves = [];
    let bestEff = 0;
    for (const m of moves) {
      const eff = getEffectiveness(m.type, this.player.types);
      if (eff > bestEff) { bestEff = eff; bestMoves = [m]; }
      else if (eff === bestEff) bestMoves.push(m);
    }

    // Among equally effective, pick highest power
    bestMoves.sort((a,b) => b.power - a.power);

    // Can we KO?
    for (const m of bestMoves) {
      const isSpec = isSpecialType(m.type);
      const A = isSpec ? this.enemy.stats.spa : this.enemy.stats.atk;
      const D = isSpec ? this.player.stats.spd : this.player.stats.def;
      const est = Math.floor(((2*this.enemy.level/5+2)*m.power*A/D)/50) + 2;
      const eff = getEffectiveness(m.type, this.player.types);
      if (est * eff >= this.player.currentHp) return m;
    }

    return bestMoves[0];
  },

  executeTurn(playerMove) {
    const enemyMove = this.chooseEnemyMove();
    if (!enemyMove) {
      // Enemy has no PP — player wins by forfeit
      this.showMessage(this.enemy.name + ' has no moves left!', () => {
        this.resultText = 'You win!';
        this.state = 'result';
      });
      return;
    }

    // Determine order by speed
    const playerFirst = this.player.stats.spe >= this.enemy.stats.spe;

    const doPlayerAttack = (cb) => {
      playerMove.pp--;
      const result = this.calcDamage(this.player, this.enemy, playerMove);
      const msgs = [this.player.name + ' used ' + playerMove.name + '!'];

      this.enemy.currentHp = Math.max(0, this.enemy.currentHp - result.damage);

      if (result.isCritical) msgs.push('A critical hit!');
      if (result.effectiveness > 1) msgs.push("It's super effective!");
      else if (result.effectiveness > 0 && result.effectiveness < 1) msgs.push("It's not very effective...");
      else if (result.effectiveness === 0) msgs.push("It doesn't affect " + this.enemy.name + '...');

      // Trigger animations
      this.shakeTarget = 'enemy';
      this.shakeTimer = 0.3;
      this.flashTarget = 'enemy';
      this.flashTimer = 0.4;
      this.criticalFlash = result.isCritical;

      this.showMessages(msgs, () => {
        if (this.enemy.currentHp <= 0) {
          this.faintTarget = 'enemy';
          this.faintTimer = 0;
          this.showMessage(this.enemy.name + ' fainted!', () => {
            this.resultText = 'You win!';
            this.state = 'result';
          });
        } else {
          cb();
        }
      });
    };

    const doEnemyAttack = (cb) => {
      enemyMove.pp--;
      const result = this.calcDamage(this.enemy, this.player, enemyMove);
      const msgs = ['Foe ' + this.enemy.name + ' used ' + enemyMove.name + '!'];

      this.player.currentHp = Math.max(0, this.player.currentHp - result.damage);

      if (result.isCritical) msgs.push('A critical hit!');
      if (result.effectiveness > 1) msgs.push("It's super effective!");
      else if (result.effectiveness > 0 && result.effectiveness < 1) msgs.push("It's not very effective...");
      else if (result.effectiveness === 0) msgs.push("It doesn't affect " + this.player.name + '...');

      this.shakeTarget = 'player';
      this.shakeTimer = 0.3;
      this.flashTarget = 'player';
      this.flashTimer = 0.4;
      this.criticalFlash = result.isCritical;

      this.showMessages(msgs, () => {
        if (this.player.currentHp <= 0) {
          this.faintTarget = 'player';
          this.faintTimer = 0;
          this.showMessage(this.player.name + ' fainted!', () => {
            this.resultText = 'You lose...';
            this.state = 'result';
          });
        } else {
          cb();
        }
      });
    };

    if (playerFirst) {
      doPlayerAttack(() => doEnemyAttack(() => { this.state = 'playerChoice'; }));
    } else {
      doEnemyAttack(() => doPlayerAttack(() => { this.state = 'playerChoice'; }));
    }
  },

  update(dt) {
    if (!this.active) return;

    // HP bar lerp
    const playerHpRatio = this.player.currentHp / this.player.stats.hp;
    const enemyHpRatio = this.enemy.currentHp / this.enemy.stats.hp;
    this.playerHpDisplay += (playerHpRatio - this.playerHpDisplay) * Math.min(1, dt * this.hpLerpSpeed * 3);
    this.enemyHpDisplay += (enemyHpRatio - this.enemyHpDisplay) * Math.min(1, dt * this.hpLerpSpeed * 3);
    if (Math.abs(this.playerHpDisplay - playerHpRatio) < 0.001) this.playerHpDisplay = playerHpRatio;
    if (Math.abs(this.enemyHpDisplay - enemyHpRatio) < 0.001) this.enemyHpDisplay = enemyHpRatio;

    // Shake & flash timers
    if (this.shakeTimer > 0) this.shakeTimer -= dt;
    if (this.flashTimer > 0) this.flashTimer -= dt;
    if (this.faintTarget) {
      this.faintTimer += dt;
    }

    switch (this.state) {
      case 'intro':
        this.introTimer += dt;
        this.enemySlideX += (148 - this.enemySlideX) * Math.min(1, dt * 5);
        this.playerSlideX += (16 - this.playerSlideX) * Math.min(1, dt * 5);
        if (this.introTimer > 1.0) {
          this.showMessage('Wild ' + this.enemy.name + ' appeared!', () => {
            this.showMessage('Go! ' + this.player.name + '!', () => {
              this.state = 'playerChoice';
            });
