const Dialog = {
  active: false,
  lines: [],
  currentLine: 0,
  charIndex: 0,
  charTimer: 0,
  charSpeed: 0.03,
  displayText: '',
  onComplete: null,
  waitingForInput: false,

  start(lines, onComplete) {
    this.active = true;
    this.lines = lines;
    this.currentLine = 0;
    this.charIndex = 0;
    this.charTimer = 0;
    this.displayText = '';
    this.onComplete = onComplete;
    this.waitingForInput = false;
  },

  update(dt) {
    if (!this.active) return;
    if (this.waitingForInput) {
      if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
        this.currentLine++;
        if (this.currentLine >= this.lines.length) {
          this.active = false;
          if (this.onComplete) this.onComplete();
          return;
        }
        this.charIndex = 0;
        this.displayText = '';
        this.waitingForInput = false;
      }
      return;
    }

    this.charTimer += dt;
    if (this.charTimer >= this.charSpeed) {
      this.charTimer = 0;
      if (this.charIndex < this.lines[this.currentLine].length) {
        this.displayText += this.lines[this.currentLine][this.charIndex];
        this.charIndex++;
      } else {
        this.waitingForInput = true;
      }
    }

    // Fast forward
    if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
      if (this.charIndex < this.lines[this.currentLine].length) {
        this.displayText = this.lines[this.currentLine];
        this.charIndex = this.lines[this.currentLine].length;
        this.waitingForInput = true;
      }
    }
  },

  draw() {
    if (!this.active) return;
    // Dialog box
    const bx = 4, by = GBA_H - 44, bw = GBA_W - 8, bh = 40;
    bctx.fillStyle = '#f8f8f8';
    bctx.fillRect(bx, by, bw, bh);
    bctx.strokeStyle = '#404040';
    bctx.lineWidth = 2;
    bctx.strokeRect(bx+1, by+1, bw-2, bh-2);
    bctx.lineWidth = 1;

    // Text
    bctx.fillStyle = '#202020';
    bctx.font = '8px monospace';
    bctx.textBaseline = 'top';

    // Word wrap
    const maxW = bw - 16;
    const words = this.displayText.split(' ');
    let line = '', lineY = by + 6;
    for (const word of words) {
      const test = line + (line ? ' ' : '') + word;
      if (bctx.measureText(test).width > maxW) {
        bctx.fillText(line, bx + 8, lineY);
        lineY += 12;
        line = word;
      } else {
        line = test;
      }
    }
    bctx.fillText(line, bx + 8, lineY);

    // Continue indicator
    if (this.waitingForInput) {
      const blinkOn = Math.floor(Date.now() / 400) % 2 === 0;
      if (blinkOn) {
        bctx.fillStyle = '#202020';
        const ax = bx + bw - 14, ay = by + bh - 10;
        bctx.beginPath();
        bctx.moveTo(ax, ay); bctx.lineTo(ax+6, ay); bctx.lineTo(ax+3, ay+4);
        bctx.fill();
      }
    }
  }
};

// ============================================================
// BATTLE TRANSITION
// ============================================================
const Transition = {
  active: false,
  phase: 0, // 0=flash, 1=mosaic, 2=fadeout
  timer: 0,
  duration: 0,
  onComplete: null,
  snapshot: null,

  start(onComplete) {
    this.active = true;
    this.phase = 0;
    this.timer = 0;
    this.duration = 0.15;
    this.onComplete = onComplete;
    // Capture current screen
    this.snapshot = bctx.getImageData(0, 0, GBA_W, GBA_H);
  },

  update(dt) {
    if (!this.active) return;
    this.timer += dt;

    if (this.phase === 0 && this.timer >= this.duration) {
      this.phase = 1; this.timer = 0; this.duration = 0.8;
    } else if (this.phase === 1 && this.timer >= this.duration) {
      this.phase = 2; this.timer = 0; this.duration = 0.5;
    } else if (this.phase === 2 && this.timer >= this.duration) {
      this.active = false;
      if (this.onComplete) this.onComplete();
    }
  },

  draw() {
    if (!this.active) return;

    if (this.phase === 0) {
      // Flash: alternate white and normal
      if (this.snapshot) bctx.putImageData(this.snapshot, 0, 0);
      const flashIntensity = Math.sin(this.timer / this.duration * Math.PI * 4);
      if (flashIntensity > 0) {
        bctx.fillStyle = `rgba(255,255,255,${flashIntensity * 0.8})`;
        bctx.fillRect(0, 0, GBA_W, GBA_H);
      }
    } else if (this.phase === 1) {
      // Mosaic effect
      if (this.snapshot) bctx.putImageData(this.snapshot, 0, 0);
      const progress = this.timer / this.duration;
      const blockSize = Math.max(1, Math.floor(progress * 24));

      // Read current pixels, mosaic them
      const imgData = bctx.getImageData(0, 0, GBA_W, GBA_H);
      const pixels = imgData.data;
      for (let by = 0; by < GBA_H; by += blockSize) {
        for (let bx = 0; bx < GBA_W; bx += blockSize) {
          // Sample center pixel
          const sx = Math.min(bx + (blockSize>>1), GBA_W-1);
          const sy = Math.min(by + (blockSize>>1), GBA_H-1);
          const si = (sy * GBA_W + sx) * 4;
          const r = pixels[si], g = pixels[si+1], b = pixels[si+2];
          // Fill block
          for (let py = by; py < Math.min(by+blockSize, GBA_H); py++) {
            for (let px = bx; px < Math.min(bx+blockSize, GBA_W); px++) {
              const di = (py * GBA_W + px) * 4;
              pixels[di] = r; pixels[di+1] = g; pixels[di+2] = b;
            }
          }
        }
      }
      bctx.putImageData(imgData, 0, 0);

      // Darken towards end
      if (progress > 0.5) {
        const darkness = (progress - 0.5) * 2;
        bctx.fillStyle = `rgba(0,0,0,${darkness})`;
        bctx.fillRect(0, 0, GBA_W, GBA_H);
      }
    } else if (this.phase === 2) {
      // Fade to black
      bctx.fillStyle = '#000';
      bctx.fillRect(0, 0, GBA_W, GBA_H);
    }
  }
};

