// BATTLE ENGINE
// ============================================================
const Battle = {
  active: false,
  state: 'intro', // intro, playerChoice, moveSelect, playerTurn, enemyTurn, message, fainted, result
  player: null,
  enemy: null,
  playerSprite: null,
  enemySprite: null,

  // Animation state
  introTimer: 0,
  playerSlideX: -96,
  enemySlideX: GBA_W + 96,

  // HP bar lerp
  playerHpDisplay: 1,
  enemyHpDisplay: 1,
  hpLerpSpeed: 0.8,

  // Message queue
  messages: [],
  currentMessage: '',
  msgCharIndex: 0,
  msgCharTimer: 0,
  msgWaiting: false,
  afterMessage: null,

  // Combat state
  selectedMove: 0,
  cursorPos: 0, // 0=Fight, 1=Bag, 2=Pokémon, 3=Run

  // Animation effects
  shakeTarget: null, // 'player' or 'enemy'
  shakeTimer: 0,
  flashTarget: null,
  flashTimer: 0,
  criticalFlash: false,

  // Slide-out for faint
  faintTarget: null,
  faintTimer: 0,

  // Result
  resultText: '',

  init(playerId, enemyId) {
    const pd = JSON.parse(JSON.stringify(POKEMON_DB[playerId]));
    const ed = JSON.parse(JSON.stringify(POKEMON_DB[enemyId]));
    pd.currentHp = pd.stats.hp;
    ed.currentHp = ed.stats.hp;

    this.player = pd;
    this.enemy = ed;
    this.playerSprite = AssetManager.get('player_back');
    this.enemySprite = AssetManager.get('enemy_front');
    this.active = true;
    this.state = 'intro';
    this.introTimer = 0;
    this.playerSlideX = -80;
    this.enemySlideX = GBA_W + 80;
    this.playerHpDisplay = 1;
    this.enemyHpDisplay = 1;
    this.messages = [];
    this.currentMessage = '';
    this.msgCharIndex = 0;
    this.shakeTarget = null;
    this.flashTarget = null;
    this.faintTarget = null;
    this.selectedMove = 0;
    this.cursorPos = 0;
    this.resultText = '';
  },

  showMessage(text, callback) {
    this.state = 'message';
    this.currentMessage = text;
    this.msgCharIndex = 0;
    this.msgCharTimer = 0;
    this.msgDisplayText = '';
    this.msgWaiting = false;
    this.afterMessage = callback || null;
  },

  showMessages(msgs, finalCallback) {
    if (msgs.length === 0) { if (finalCallback) finalCallback(); return; }
    const msg = msgs.shift();
    this.showMessage(msg, () => this.showMessages(msgs, finalCallback));
  },

  // Gen3 damage formula
  calcDamage(attacker, defender, move) {
    const level = attacker.level;
    const power = move.power;
    const isSpecial = isSpecialType(move.type);
    const A = isSpecial ? attacker.stats.spa : attacker.stats.atk;
    const D = isSpecial ? defender.stats.spd : defender.stats.def;

    let damage = Math.floor(((2 * level / 5 + 2) * power * A / D) / 50) + 2;

    // Critical hit (6.25% = 1/16)
    const isCritical = Math.random() < 1/16;
    if (isCritical) damage *= 2;

    // STAB
    const hasStab = attacker.types.includes(move.type);
    if (hasStab) damage = Math.floor(damage * 1.5);

    // Type effectiveness
    const effectiveness = getEffectiveness(move.type, defender.types);
    damage = Math.floor(damage * effectiveness);

    // Random factor (85-100)/100
    const rand = Math.floor(Math.random() * 16 + 85) / 100;
    damage = Math.floor(damage * rand);

    return { damage: Math.max(1, damage), isCritical, effectiveness, hasStab };
  },

  // Enemy AI
  chooseEnemyMove() {
    const moves = this.enemy.moves.filter(m => m.pp > 0);
    if (moves.length === 0) return null;

    // Prioritize super effective moves
    let bestMoves = [];
    let bestEff = 0;
    for (const m of moves) {
      const eff = getEffectiveness(m.type, this.player.types);
      if (eff > bestEff) { bestEff = eff; bestMoves = [m]; }
      else if (eff === bestEff) bestMoves.push(m);
    }

    // Among equally effective, pick highest power
    bestMoves.sort((a,b) => b.power - a.power);

    // Can we KO?
    for (const m of bestMoves) {
      const isSpec = isSpecialType(m.type);
      const A = isSpec ? this.enemy.stats.spa : this.enemy.stats.atk;
      const D = isSpec ? this.player.stats.spd : this.player.stats.def;
      const est = Math.floor(((2*this.enemy.level/5+2)*m.power*A/D)/50) + 2;
      const eff = getEffectiveness(m.type, this.player.types);
      if (est * eff >= this.player.currentHp) return m;
    }

    return bestMoves[0];
  },

  executeTurn(playerMove) {
    const enemyMove = this.chooseEnemyMove();
    if (!enemyMove) {
      // Enemy has no PP — player wins by forfeit
      this.showMessage(this.enemy.name + ' has no moves left!', () => {
        this.resultText = 'You win!';
        this.state = 'result';
      });
      return;
    }

    // Determine order by speed
    const playerFirst = this.player.stats.spe >= this.enemy.stats.spe;

    const doPlayerAttack = (cb) => {
      playerMove.pp--;
      const result = this.calcDamage(this.player, this.enemy, playerMove);
      const msgs = [this.player.name + ' used ' + playerMove.name + '!'];

      this.enemy.currentHp = Math.max(0, this.enemy.currentHp - result.damage);

      if (result.isCritical) msgs.push('A critical hit!');
      if (result.effectiveness > 1) msgs.push("It's super effective!");
      else if (result.effectiveness > 0 && result.effectiveness < 1) msgs.push("It's not very effective...");
      else if (result.effectiveness === 0) msgs.push("It doesn't affect " + this.enemy.name + '...');

      // Trigger animations
      this.shakeTarget = 'enemy';
      this.shakeTimer = 0.3;
      this.flashTarget = 'enemy';
      this.flashTimer = 0.4;
      this.criticalFlash = result.isCritical;

      this.showMessages(msgs, () => {
        if (this.enemy.currentHp <= 0) {
          this.faintTarget = 'enemy';
          this.faintTimer = 0;
          this.showMessage(this.enemy.name + ' fainted!', () => {
            this.resultText = 'You win!';
            this.state = 'result';
          });
        } else {
          cb();
        }
      });
    };

    const doEnemyAttack = (cb) => {
      enemyMove.pp--;
      const result = this.calcDamage(this.enemy, this.player, enemyMove);
      const msgs = ['Foe ' + this.enemy.name + ' used ' + enemyMove.name + '!'];

      this.player.currentHp = Math.max(0, this.player.currentHp - result.damage);

      if (result.isCritical) msgs.push('A critical hit!');
      if (result.effectiveness > 1) msgs.push("It's super effective!");
      else if (result.effectiveness > 0 && result.effectiveness < 1) msgs.push("It's not very effective...");
      else if (result.effectiveness === 0) msgs.push("It doesn't affect " + this.player.name + '...');

      this.shakeTarget = 'player';
      this.shakeTimer = 0.3;
      this.flashTarget = 'player';
      this.flashTimer = 0.4;
      this.criticalFlash = result.isCritical;

      this.showMessages(msgs, () => {
        if (this.player.currentHp <= 0) {
          this.faintTarget = 'player';
          this.faintTimer = 0;
          this.showMessage(this.player.name + ' fainted!', () => {
            this.resultText = 'You lose...';
            this.state = 'result';
          });
        } else {
          cb();
        }
      });
    };

    if (playerFirst) {
      doPlayerAttack(() => doEnemyAttack(() => { this.state = 'playerChoice'; }));
    } else {
      doEnemyAttack(() => doPlayerAttack(() => { this.state = 'playerChoice'; }));
    }
  },

  update(dt) {
    if (!this.active) return;

    // HP bar lerp
    const playerHpRatio = this.player.currentHp / this.player.stats.hp;
    const enemyHpRatio = this.enemy.currentHp / this.enemy.stats.hp;
    this.playerHpDisplay += (playerHpRatio - this.playerHpDisplay) * Math.min(1, dt * this.hpLerpSpeed * 3);
    this.enemyHpDisplay += (enemyHpRatio - this.enemyHpDisplay) * Math.min(1, dt * this.hpLerpSpeed * 3);
    if (Math.abs(this.playerHpDisplay - playerHpRatio) < 0.001) this.playerHpDisplay = playerHpRatio;
    if (Math.abs(this.enemyHpDisplay - enemyHpRatio) < 0.001) this.enemyHpDisplay = enemyHpRatio;

    // Shake & flash timers
    if (this.shakeTimer > 0) this.shakeTimer -= dt;
    if (this.flashTimer > 0) this.flashTimer -= dt;
    if (this.faintTarget) {
      this.faintTimer += dt;
    }

    switch (this.state) {
      case 'intro':
        this.introTimer += dt;
        this.enemySlideX += (148 - this.enemySlideX) * Math.min(1, dt * 5);
        this.playerSlideX += (16 - this.playerSlideX) * Math.min(1, dt * 5);
        if (this.introTimer > 1.0) {
          this.showMessage('Wild ' + this.enemy.name + ' appeared!', () => {
            this.showMessage('Go! ' + this.player.name + '!', () => {
              this.state = 'playerChoice';
            });
          });
        }
        break;

      case 'playerChoice':
        if (Input.wasPressed('ArrowLeft') || Input.wasPressed('ArrowRight')) {
          this.cursorPos ^= 1;
        }
        if (Input.wasPressed('ArrowUp') || Input.wasPressed('ArrowDown')) {
          this.cursorPos ^= 2;
        }
        if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
          if (this.cursorPos === 0) {
            this.state = 'moveSelect';
            this.selectedMove = 0;
          } else if (this.cursorPos === 3) {
            // Run
            if (Math.random() < 0.5) {
              this.showMessage('Got away safely!', () => {
                this.active = false;
                Game.state = 'map';
              });
            } else {
              this.showMessage("Can't escape!", () => {
                // Enemy attacks
                const em = this.chooseEnemyMove();
                if (em) {
                  em.pp--;
                  const r = this.calcDamage(this.enemy, this.player, em);
                  this.player.currentHp = Math.max(0, this.player.currentHp - r.damage);
                  this.shakeTarget = 'player'; this.shakeTimer = 0.3;
                  this.flashTarget = 'player'; this.flashTimer = 0.4;
                  const msgs = ['Foe ' + this.enemy.name + ' used ' + em.name + '!'];
                  if (r.isCritical) msgs.push('A critical hit!');
                  if (r.effectiveness > 1) msgs.push("It's super effective!");
                  this.showMessages(msgs, () => {
                    if (this.player.currentHp <= 0) {
                      this.faintTarget = 'player'; this.faintTimer = 0;
                      this.showMessage(this.player.name + ' fainted!', () => {
                        this.resultText = 'You lose...';
                        this.state = 'result';
                      });
                    } else {
                      this.state = 'playerChoice';
                    }
                  });
                } else {
                  this.state = 'playerChoice';
                }
              });
            }
          } else {
            // Bag / Pokémon: not implemented
            this.showMessage('No items or Pokémon available!', () => {
              this.state = 'playerChoice';
            });
          }
        }
        break;

      case 'moveSelect':
        if (Input.wasPressed('ArrowLeft') || Input.wasPressed('ArrowRight')) {
          this.selectedMove ^= 1;
        }
        if (Input.wasPressed('ArrowUp') || Input.wasPressed('ArrowDown')) {
          this.selectedMove ^= 2;
        }
        if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
          const move = this.player.moves[this.selectedMove];
          if (move && move.pp > 0) {
            this.executeTurn(move);
          }
        }
        if (Input.wasPressed('KeyX') || Input.wasPressed('Backspace')) {
          this.state = 'playerChoice';
        }
        break;

      case 'message':
        this.msgCharTimer += dt;
        if (this.msgCharTimer >= 0.03) {
          this.msgCharTimer = 0;
          if (this.msgCharIndex < this.currentMessage.length) {
            this.msgDisplayText = (this.msgDisplayText || '') + this.currentMessage[this.msgCharIndex];
            this.msgCharIndex++;
          } else {
            this.msgWaiting = true;
          }
        }
        if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
          if (!this.msgWaiting) {
            this.msgDisplayText = this.currentMessage;
            this.msgCharIndex = this.currentMessage.length;
            this.msgWaiting = true;
          } else {
            if (this.afterMessage) this.afterMessage();
          }
        }
        break;

      case 'result':
        if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
          this.active = false;
          Game.state = 'map';
          Game.battleDone = true;
        }
        break;
    }
  },

  draw() {
    if (!this.active) return;

    // Battle background
    // Sky gradient
    for (let y = 0; y < 80; y++) {
      const t = y / 80;
      const r = Math.floor(112 + t * 60);
      const g = Math.floor(168 + t * 40);
      const b = Math.floor(248 - t * 40);
      bctx.fillStyle = `rgb(${r},${g},${b})`;
      bctx.fillRect(0, y, GBA_W, 1);
    }
    // Ground
    bctx.fillStyle = '#90c868';
    bctx.fillRect(0, 80, GBA_W, 40);
    bctx.fillStyle = '#78b050';
    bctx.fillRect(0, 88, GBA_W, 32);

    // Battle platforms
    // Enemy platform (top right)
    bctx.fillStyle = '#60a040';
    bctx.beginPath();
    bctx.ellipse(180, 72, 50, 10, 0, 0, Math.PI*2);
    bctx.fill();
    bctx.fillStyle = '#509030';
    bctx.beginPath();
    bctx.ellipse(180, 74, 50, 10, 0, 0, Math.PI*2);
    bctx.fill();

    // Player platform (bottom left)
    bctx.fillStyle = '#60a040';
    bctx.beginPath();
    bctx.ellipse(60, 112, 50, 10, 0, 0, Math.PI*2);
    bctx.fill();
    bctx.fillStyle = '#509030';
    bctx.beginPath();
    bctx.ellipse(60, 114, 50, 10, 0, 0, Math.PI*2);
    bctx.fill();

    // Draw Pokemon sprites
    const drawPokemonSprite = (sprite, x, y, size, target) => {
      let dx = 0, dy = 0;
      // Shake effect
      if (this.shakeTarget === target && this.shakeTimer > 0) {
        dx = Math.sin(this.shakeTimer * 40) * 3;
      }
      // Faint animation
      if (this.faintTarget === target) {
        const faintProgress = Math.min(1, this.faintTimer / 0.5);
        if (target === 'enemy') {
          // Slide down and fade
          dy = faintProgress * 40;
          bctx.globalAlpha = 1 - faintProgress;
        } else {
          dy = faintProgress * 40;
          bctx.globalAlpha = 1 - faintProgress;
        }
      }
      // Flash effect
      const shouldHide = this.flashTarget === target && this.flashTimer > 0 &&
                         Math.floor(this.flashTimer * 12) % 2 === 0;

      if (!shouldHide) {
        if (sprite) {
          bctx.drawImage(sprite, x + dx, y + dy, size, size);
        } else {
          // Placeholder
          bctx.fillStyle = target === 'player' ? '#e04040' : '#6060e0';
          bctx.fillRect(x + dx + 8, y + dy + 8, size - 16, size - 16);
          bctx.fillStyle = '#fff';
          bctx.font = '6px monospace';
          bctx.textAlign = 'center';
          bctx.fillText(target === 'player' ? this.player.name : this.enemy.name,
                        x + dx + size/2, y + dy + size/2);
          bctx.textAlign = 'left';
        }
      }
      bctx.globalAlpha = 1;
    };

    // Enemy sprite (front, top right)
    const esx = this.state === 'intro' ? this.enemySlideX : 148;
    drawPokemonSprite(this.enemySprite, esx, 12, 64, 'enemy');

    // Player sprite (back, bottom left)
    const psx = this.state === 'intro' ? this.playerSlideX : 16;
    drawPokemonSprite(this.playerSprite, psx, 48, 64, 'player');

    // Enemy HP bar (top left)
    this.drawHpBar(8, 16, this.enemy.name, this.enemy.level,
                   this.enemyHpDisplay, false);

    // Player HP bar (bottom right)
    this.drawHpBar(120, 80, this.player.name, this.player.level,
                   this.playerHpDisplay, true);

    // Bottom panel (below battle field)
    bctx.fillStyle = '#f8f8f8';
    bctx.fillRect(0, 120, GBA_W, 40);
    bctx.strokeStyle = '#404040';
    bctx.lineWidth = 2;
    bctx.strokeRect(1, 120, GBA_W-2, 39);
    bctx.lineWidth = 1;

    if (this.state === 'playerChoice') {
      // "What will PLAYER do?"
      bctx.fillStyle = '#202020';
      bctx.font = '8px monospace';
      bctx.fillText('What will', 8, 132);
      bctx.fillText(this.player.name + ' do?', 8, 144);

      // Buttons: Fight/Bag/Pokémon/Run
      const labels = ['FIGHT', 'BAG', 'POKéMON', 'RUN'];
      const colors = ['#f08030', '#48a030', '#6890f0', '#78c850'];
      for (let i = 0; i < 4; i++) {
        const bx = 120 + (i % 2) * 58;
        const by = 123 + Math.floor(i / 2) * 18;
        bctx.fillStyle = colors[i];
        bctx.fillRect(bx, by, 54, 15);
        bctx.strokeStyle = '#303030';
        bctx.strokeRect(bx, by, 54, 15);
        bctx.fillStyle = '#fff';
        bctx.font = '7px monospace';
        bctx.fillText(labels[i], bx + 4, by + 11);

        if (i === this.cursorPos) {
          bctx.strokeStyle = '#f8e030';
          bctx.lineWidth = 2;
          bctx.strokeRect(bx-1, by-1, 56, 17);
          bctx.lineWidth = 1;
        }
      }
    } else if (this.state === 'moveSelect') {
      // Show 4 moves
      for (let i = 0; i < 4; i++) {
        const move = this.player.moves[i];
        if (!move) continue;
        const bx = 4 + (i % 2) * 118;
        const by = 123 + Math.floor(i / 2) * 18;

        bctx.fillStyle = TYPE_COLORS[move.type] || '#888';
        bctx.fillRect(bx, by, 114, 15);
        bctx.strokeStyle = '#303030';
        bctx.strokeRect(bx, by, 114, 15);

        bctx.fillStyle = '#fff';
        bctx.font = '7px monospace';
        bctx.fillText(move.name, bx+3, by+10);

        bctx.fillStyle = '#ffe';
        bctx.font = '6px monospace';
        bctx.fillText('PP ' + move.pp + '/' + move.maxPp, bx+76, by+10);

        if (i === this.selectedMove) {
          bctx.strokeStyle = '#f8e030';
          bctx.lineWidth = 2;
          bctx.strokeRect(bx-1, by-1, 116, 17);
          bctx.lineWidth = 1;
        }
      }
    } else if (this.state === 'message' || this.state === 'intro') {
      // Message box
      bctx.fillStyle = '#202020';
      bctx.font = '8px monospace';
      const text = this.msgDisplayText || '';
      // Word wrap
      const maxW = GBA_W - 20;
      const words = text.split(' ');
      let line = '', lineY = 132;
      for (const word of words) {
        const test = line + (line ? ' ' : '') + word;
        if (bctx.measureText(test).width > maxW && line) {
          bctx.fillText(line, 8, lineY);
          lineY += 12;
          line = word;
        } else {
          line = test;
        }
      }
      bctx.fillText(line, 8, lineY);

      if (this.msgWaiting) {
        const blinkOn = Math.floor(Date.now() / 400) % 2 === 0;
        if (blinkOn) {
          bctx.fillStyle = '#202020';
          const ax = GBA_W - 16, ay = 152;
          bctx.beginPath();
          bctx.moveTo(ax, ay); bctx.lineTo(ax+6, ay); bctx.lineTo(ax+3, ay+4);
          bctx.fill();
        }
      }
    } else if (this.state === 'result') {
      bctx.fillStyle = '#202020';
      bctx.font = '10px monospace';
      bctx.textAlign = 'center';
      bctx.fillText(this.resultText, GBA_W/2, 140);
      bctx.font = '7px monospace';
      bctx.fillText('Press Z to continue', GBA_W/2, 153);
      bctx.textAlign = 'left';
    }
  },

  drawHpBar(x, y, name, level, hpRatio, showHpText) {
    const w = 110, h = 28;

    // Trapezoidal frame background
    bctx.fillStyle = '#303030';
    bctx.beginPath();
    bctx.moveTo(x + 6, y);
    bctx.lineTo(x + w, y);
    bctx.lineTo(x + w, y + h);
    bctx.lineTo(x, y + h);
    bctx.closePath();
    bctx.fill();

    // Inner background
    bctx.fillStyle = '#f0e8d0';
    bctx.beginPath();
    bctx.moveTo(x + 8, y + 2);
    bctx.lineTo(x + w - 2, y + 2);
    bctx.lineTo(x + w - 2, y + h - 2);
    bctx.lineTo(x + 2, y + h - 2);
    bctx.closePath();
    bctx.fill();

    // Name
    bctx.fillStyle = '#202020';
    bctx.font = '8px monospace';
    bctx.fillText(name, x + 10, y + 12);

    // Level
    bctx.fillStyle = '#606060';
    bctx.font = '7px monospace';
    bctx.fillText('Lv' + level, x + w - 30, y + 12);

    // HP bar track
    const barX = x + 28, barY = y + 16, barW = 72, barH = 4;
    bctx.fillStyle = '#404040';
    bctx.fillRect(barX - 1, barY - 1, barW + 2, barH + 2);
    bctx.fillStyle = '#202020';
    bctx.fillRect(barX, barY, barW, barH);

    // HP bar fill
    const fillW = Math.max(0, Math.floor(barW * Math.max(0, hpRatio)));
    let barColor;
    if (hpRatio > 0.5) barColor = '#40c040';
    else if (hpRatio > 0.2) barColor = '#e0c030';
    else barColor = '#e04040';
    bctx.fillStyle = barColor;
    bctx.fillRect(barX, barY, fillW, barH);

    // "HP" label
    bctx.fillStyle = '#f08030';
    bctx.font = 'bold 6px monospace';
    bctx.fillText('HP', x + 12, y + 20);

    // HP numbers (player side only)
    if (showHpText) {
      const current = Math.ceil(hpRatio * this.player.stats.hp);
      bctx.fillStyle = '#202020';
      bctx.font = '7px monospace';
      bctx.textAlign = 'right';
      bctx.fillText(Math.max(0, current) + '/' + this.player.stats.hp, x + w - 4, y + h - 4);
      bctx.textAlign = 'left';
    }
  }
};

// ============================================================
// GAME LOOP
// ============================================================
const Game = {
  state: 'loading', // loading, title, map, transition, battle
  battleDone: false,
  lastTime: 0,

  async init() {
    Input.init();

    // Queue sprite assets
    AssetManager.queue('player_back',
      'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/back/6.png');
    AssetManager.queue('enemy_front',
      'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/150.png');

    this.state = 'loading';
    await AssetManager.loadAll();
    this.state = 'title';

    this.lastTime = performance.now();
    requestAnimationFrame(t => this.loop(t));
  },

  loop(time) {
    const dt = Math.min(0.1, (time - this.lastTime) / 1000);
    this.lastTime = time;

    this.update(dt);
    this.render();
    Input.clear();
    requestAnimationFrame(t => this.loop(t));
  },

  update(dt) {
    switch (this.state) {
      case 'loading':
        break;
      case 'title':
        if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
          this.state = 'map';
        }
        break;
      case 'map':
        if (!Dialog.active) {
          Player.update(dt);
          if (!Player.moving && isFacingNPC() && !this.battleDone &&
              (Input.wasPressed('KeyZ') || Input.wasPressed('Enter'))) {
            Dialog.start([
              'RIVAL: Hey! You made it!',
              'RIVAL: I\'ve been waiting to battle you!',
              'RIVAL: Let\'s see what your CHARIZARD can do against my MEWTWO!',
              'RIVAL: Get ready!'
            ], () => {
              this.state = 'transition';
              Transition.start(() => {
                Battle.init(6, 150);
                this.state = 'battle';
              });
            });
          }
        }
        Dialog.update(dt);
        break;
      case 'transition':
        Transition.update(dt);
        break;
      case 'battle':
        Battle.update(dt);
        break;
    }
  },

  render() {
    bctx.clearRect(0, 0, GBA_W, GBA_H);

    switch (this.state) {
      case 'loading':
        bctx.fillStyle = '#000';
        bctx.fillRect(0, 0, GBA_W, GBA_H);
        bctx.fillStyle = '#fff';
        bctx.font = '10px monospace';
        bctx.textAlign = 'center';
        bctx.fillText('Loading...', GBA_W/2, GBA_H/2 - 8);
        // Progress bar
        const prog = AssetManager.progress();
        bctx.fillStyle = '#333';
        bctx.fillRect(60, GBA_H/2 + 4, 120, 8);
        bctx.fillStyle = '#4a8';
        bctx.fillRect(60, GBA_H/2 + 4, Math.floor(120 * prog), 8);
        bctx.textAlign = 'left';
        break;

      case 'title':
        bctx.fillStyle = '#000';
        bctx.fillRect(0, 0, GBA_W, GBA_H);

        // Title
        bctx.fillStyle = '#f8d030';
        bctx.font = 'bold 14px monospace';
        bctx.textAlign = 'center';
        bctx.fillText('POKéMON', GBA_W/2, 50);
        bctx.fillStyle = '#f08030';
        bctx.font = 'bold 10px monospace';
        bctx.fillText('GEN III BATTLE', GBA_W/2, 68);

        // Flashing prompt
        if (Math.floor(Date.now() / 600) % 2 === 0) {
          bctx.fillStyle = '#fff';
          bctx.font = '8px monospace';
          bctx.fillText('PRESS Z TO START', GBA_W/2, 110);
        }

        bctx.fillStyle = '#888';
        bctx.font = '6px monospace';
        bctx.fillText('Arrow Keys: Move | Z: Interact/Confirm | X: Back', GBA_W/2, 140);
        bctx.textAlign = 'left';
        break;

      case 'map':
      case 'transition':
        // Draw map
        // Camera follows player
        const camX = Math.floor(Player.px - GBA_W/2 + TILE/2);
        const camY = Math.floor(Player.py - GBA_H/2 + TILE/2);

        bctx.save();
        bctx.translate(-camX, -camY);

        // Draw visible tiles
        const startTX = Math.max(0, Math.floor(camX / TILE));
        const startTY = Math.max(0, Math.floor(camY / TILE));
        const endTX = Math.min(MAP_W, Math.ceil((camX + GBA_W) / TILE) + 1);
        const endTY = Math.min(MAP_H, Math.ceil((camY + GBA_H) / TILE) + 1);

        for (let ty = startTY; ty < endTY; ty++) {
          for (let tx = startTX; tx < endTX; tx++) {
            drawTile(tx, ty, MAP_DATA[ty][tx]);
          }
        }

        NPC.draw();
        Player.draw();

        bctx.restore();

        Dialog.draw();

        if (this.state === 'transition') {
          Transition.draw();
        }

        // Post-battle message
        if (this.battleDone) {
          bctx.fillStyle = 'rgba(0,0,0,0.5)';
          bctx.fillRect(20, 4, GBA_W - 40, 16);
          bctx.fillStyle = '#fff';
          bctx.font = '7px monospace';
          bctx.textAlign = 'center';
          bctx.fillText('Battle complete! Explore the map.', GBA_W/2, 15);
          bctx.textAlign = 'left';
        }
        break;

      case 'battle':
        Battle.draw();
        break;
    }

    // Scale buffer to display canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(buf, 0, 0, GBA_W, GBA_H, 0, 0, canvas.width, canvas.height);
  }
};

// Start game
Game.init();
</script>
</body>
</html>
"}

