  active: false,
  lines: [],
  currentLine: 0,
  charIndex: 0,
  charTimer: 0,
  charSpeed: 0.03,
  displayText: '',
  onComplete: null,
  waitingForInput: false,

  start(lines, onComplete) {
    this.active = true;

[1005 more lines in file. Use offset=500 to continue.]

    this.lines = lines;
    this.currentLine = 0;
    this.charIndex = 0;
    this.charTimer = 0;
    this.displayText = '';
    this.onComplete = onComplete;
    this.waitingForInput = false;
  },

  update(dt) {
    if (!this.active) return;
    if (this.waitingForInput) {
      if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
        this.currentLine++;
        if (this.currentLine >= this.lines.length) {
          this.active = false;
          if (this.onComplete) this.onComplete();
          return;
        }
        this.charIndex = 0;
        this.displayText = '';
        this.waitingForInput = false;
      }
      return;
    }

    this.charTimer += dt;
    if (this.charTimer >= this.charSpeed) {
      this.charTimer = 0;
      if (this.charIndex < this.lines[this.currentLine].length) {
        this.displayText += this.lines[this.currentLine][this.charIndex];
        this.charIndex++;
      } else {
        this.waitingForInput = true;
      }
    }

    // Fast forward
    if (Input.wasPressed('KeyZ') || Input.wasPressed('Enter')) {
      if (this.charIndex < this.lines[this.currentLine].length) {
        this.displayText = this.lines[this.currentLine];
        this.charIndex = this.lines[this.currentLine].length;
        this.waitingForInput = true;
      }
    }
  },

  draw() {
    if (!this.active) return;
    // Dialog box
    const bx = 4, by = GBA_H - 44, bw = GBA_W - 8, bh = 40;
    bctx.fillStyle = '#f8f8f8';
    bctx.fillRect(bx, by, bw, bh);
    bctx.strokeStyle = '#404040';
    bctx.lineWidth = 2;
    bctx.strokeRect(bx+1, by+1, bw-2, bh-2);
    bctx.lineWidth = 1;

    // Text
    bctx.fillStyle = '#202020';
    bctx.font = '8px monospace';
    bctx.textBaseline = 'top';

    // Word wrap
    const maxW = bw - 16;
    const words = this.displayText.split(' ');
    let line = '', lineY = by + 6;
    for (const word of words) {
      const test = line + (line ? ' ' : '') + word;
      if (bctx.measureText(test).width > maxW) {
        bctx.fillText(line, bx + 8, lineY);
        lineY += 12;
        line = word;
      } else {
        line = test;
      }
    }
    bctx.fillText(line, bx + 8, lineY);

    // Continue indicator
    if (this.waitingForInput) {
      const blinkOn = Math.floor(Date.now() / 400) % 2 === 0;
      if (blinkOn) {
        bctx.fillStyle = '#202020';
        const ax = bx + bw - 14, ay = by + bh - 10;
        bctx.beginPath();
        bctx.moveTo(ax, ay); bctx.lineTo(ax+6, ay); bctx.lineTo(ax+3, ay+4);
        bctx.fill();
      }
    }
  }
};

